const CONFIG = {
  maxSendsPerRun: 50,
  minSecondsBetweenMessages: 20,
  enforceQuietHours: true,
  quietStartHour: 9,
  quietEndHour: 20,
  defaultChannel: 'sms',
  defaultTemplate: 'Hi {{first_name}}, {{offer_text}} {{offer_url}} Reply STOP to opt out.',
};

function present(value) {
  return value !== undefined && value !== null && String(value).trim() !== '';
}

function pick(row, names) {
  for (const name of names) {
    if (present(row[name])) return row[name];
  }
  return '';
}

function cleanPhone(value) {
  if (!present(value)) return '';
  const text = String(value).trim();
  if (text.startsWith('+')) return '+' + text.slice(1).replace(/\D/g, '');
  return text.replace(/[^\d+]/g, '');
}

function yes(value) {
  return value === true || ['yes', 'true', '1', 'subscribed', 'opted in', 'opt-in', 'ok'].includes(String(value ?? '').trim().toLowerCase());
}

function normalizeChannel(value) {
  const channel = String(value || CONFIG.defaultChannel).trim().toLowerCase();
  return ['sms', 'rcs'].includes(channel) ? channel : CONFIG.defaultChannel;
}

function formatScheduledAt(date) {
  const pad = (part) => String(part).padStart(2, '0');
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())} ${pad(date.getHours())}:${pad(date.getMinutes())}:${pad(date.getSeconds())}`;
}

function render(template, variables) {
  return String(template || '').replace(/{{\s*([a-zA-Z0-9_]+)\s*}}/g, (_, key) => String(variables[key] ?? ''));
}

function shortMessage(message) {
  const text = String(message || '').replace(/\s+/g, ' ').trim();
  const withOptOut = /\bstop\b/i.test(text) ? text : `${text} Reply STOP to opt out.`;
  return withOptOut.length > 320 ? `${withOptOut.slice(0, 317)}...` : withOptOut;
}

const now = new Date();
const currentHour = now.getHours();
const insideSendingHours = currentHour >= CONFIG.quietStartHour && currentHour < CONFIG.quietEndHour;
const rows = $input.all();
const seenPhones = new Set();
let eligibleCount = 0;

return rows.map((item, index) => {
  const row = item.json;
  const messageId = String(pick(row, ['message_id', 'Message ID', 'id', 'ID']) || '').trim();
  const campaignName = String(pick(row, ['campaign_name', 'Campaign Name', 'campaign', 'Campaign']) || 'marketing campaign').trim();
  const phone = cleanPhone(pick(row, ['phone', 'Phone', 'mobile', 'Mobile', 'to', 'To']));
  const firstName = String(pick(row, ['first_name', 'First Name', 'firstName', 'name', 'Name']) || 'there').trim();
  const lastName = String(pick(row, ['last_name', 'Last Name', 'lastName']) || '').trim();
  const segment = String(pick(row, ['segment', 'Segment', 'audience', 'Audience']) || '').trim();
  const status = String(pick(row, ['status', 'Status', 'campaign_status', 'Campaign Status']) || '').trim().toLowerCase();
  const offerText = String(pick(row, ['offer_text', 'Offer Text', 'offer', 'Offer']) || 'we have an update for you.').trim();
  const offerUrl = String(pick(row, ['offer_url', 'Offer URL', 'url', 'URL']) || '').trim();
  const template = pick(row, ['message_template', 'Message Template', 'message', 'Message']) || CONFIG.defaultTemplate;
  const sendAfterValue = pick(row, ['send_after', 'Send After', 'sendAfter']);
  const sendAfter = present(sendAfterValue) ? new Date(sendAfterValue) : null;
  const channel = normalizeChannel(pick(row, ['channel', 'Channel']));
  const errors = [];

  if (!messageId) errors.push('Missing message_id');
  if (!phone) errors.push('Missing phone');
  if (!['ready', 'to_send', 'to send', 'pending'].includes(status)) errors.push('Status is not ready');
  if (!yes(pick(row, ['consent', 'Consent', 'sms_consent', 'SMS Consent', 'marketing_consent', 'Marketing Consent', 'opt_in', 'Opt In']))) errors.push('Missing SMS/RCS marketing consent');
  if (yes(pick(row, ['opt_out', 'Opt Out', 'suppressed', 'Suppressed', 'unsubscribe', 'Unsubscribe']))) errors.push('Contact opted out');
  if (CONFIG.enforceQuietHours && !insideSendingHours) errors.push('Outside configured sending hours');
  if (phone && seenPhones.has(phone)) errors.push('Duplicate phone in this run');
  if (sendAfter && !Number.isNaN(sendAfter.getTime()) && sendAfter > now) errors.push('Send-after time has not arrived');
  if (eligibleCount >= CONFIG.maxSendsPerRun) errors.push('Run send limit reached');

  if (phone) seenPhones.add(phone);

  const message = shortMessage(render(template, {
    first_name: firstName,
    last_name: lastName,
    offer_text: offerText,
    offer_url: offerUrl,
    campaign_name: campaignName,
    segment,
    channel,
  }));

  const eligible = errors.length === 0;
  const scheduledDate = new Date(now.getTime() + eligibleCount * CONFIG.minSecondsBetweenMessages * 1000);
  const scheduledAt = eligible ? formatScheduledAt(scheduledDate) : '';
  if (eligible) eligibleCount += 1;

  return {
    json: {
      eligible,
      skipReason: errors.join('; '),
      messageId: messageId || `row-${index + 2}`,
      campaignName,
      phone,
      channel,
      firstName,
      lastName,
      segment,
      status,
      message,
      scheduledAt,
      sourceRow: row.row_number || row.__rowNumber || index + 2,
    },
  };
});

function present(value) {
  return value !== undefined && value !== null && String(value).trim() !== '';
}

function cleanPhone(value) {
  if (!present(value)) return '';
  const text = String(value).trim();
  if (text.startsWith('+')) return '+' + text.slice(1).replace(/\D/g, '');
  return text.replace(/[^\d+]/g, '');
}

const payload = $json.body ?? $json;
const message = String(payload.message ?? payload.text ?? payload.body ?? '').trim();
const phone = cleanPhone(payload.from ?? payload.fromPhone ?? payload.phone ?? payload.sender ?? payload.to);
const keywordMatch = message.match(/\b(STOP|UNSUBSCRIBE|CANCEL|END|QUIT)\b/i);

return [{
  json: {
    isOptOut: Boolean(phone && keywordMatch),
    phone,
    keyword: keywordMatch ? keywordMatch[1].toUpperCase() : '',
    message,
    source: payload.source ?? 'inbound marketing reply',
    receivedAt: new Date().toISOString(),
  },
}];
